CREATE DATABASE IF NOT EXISTS library_management CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE library_management;
SET FOREIGN_KEY_CHECKS=0;
DROP TABLE IF EXISTS book_returns; DROP TABLE IF EXISTS borrows; DROP TABLE IF EXISTS magazines; DROP TABLE IF EXISTS newspapers; DROP TABLE IF EXISTS books; DROP TABLE IF EXISTS members; DROP TABLE IF EXISTS book_types; DROP TABLE IF EXISTS users; DROP TABLE IF EXISTS roles;
SET FOREIGN_KEY_CHECKS=1;
CREATE TABLE roles(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(50) NOT NULL UNIQUE,display_name VARCHAR(100) NOT NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE users(id INT AUTO_INCREMENT PRIMARY KEY,full_name VARCHAR(150) NOT NULL,email VARCHAR(150) NOT NULL UNIQUE,phone VARCHAR(30) NULL,student_code VARCHAR(50) NULL,class_name VARCHAR(100) NULL,major VARCHAR(150) NULL,password VARCHAR(255) NOT NULL,role_id INT NOT NULL,status ENUM('active','inactive') NOT NULL DEFAULT 'active',api_token VARCHAR(100) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,CONSTRAINT fk_users_role FOREIGN KEY(role_id) REFERENCES roles(id)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE book_types(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(150) NOT NULL UNIQUE,description TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE books(id INT AUTO_INCREMENT PRIMARY KEY,isbn VARCHAR(50) NOT NULL UNIQUE,title VARCHAR(255) NOT NULL,book_type_id INT NOT NULL,author VARCHAR(150) NOT NULL,publisher VARCHAR(150) NULL,publish_year INT NULL,quantity INT NOT NULL DEFAULT 0,price DECIMAL(12,2) NOT NULL DEFAULT 0,description TEXT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,CONSTRAINT fk_books_type FOREIGN KEY(book_type_id) REFERENCES book_types(id),CONSTRAINT chk_books_quantity CHECK(quantity>=0)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE newspapers(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255) NOT NULL,type VARCHAR(100) NULL,language VARCHAR(80) NULL,receipt_date DATE NULL,published_date DATE NULL,pages INT DEFAULT 0,quantity INT NOT NULL DEFAULT 1,price DECIMAL(12,2) DEFAULT 0,publisher VARCHAR(150) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT chk_newspapers_quantity CHECK(quantity>=0)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE magazines(id INT AUTO_INCREMENT PRIMARY KEY,name VARCHAR(255) NOT NULL,type VARCHAR(100) NULL,language VARCHAR(80) NULL,receipt_date DATE NULL,published_date DATE NULL,pages INT DEFAULT 0,quantity INT NOT NULL DEFAULT 1,price DECIMAL(12,2) DEFAULT 0,publisher VARCHAR(150) NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT chk_magazines_quantity CHECK(quantity>=0)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE members(id INT AUTO_INCREMENT PRIMARY KEY,member_code VARCHAR(50) NOT NULL UNIQUE,full_name VARCHAR(150) NOT NULL,student_code VARCHAR(50) NULL,class_name VARCHAR(100) NULL,major VARCHAR(150) NULL,phone VARCHAR(30) NULL,email VARCHAR(150) NULL,identity_number VARCHAR(50) NULL,address TEXT NULL,status ENUM('active','inactive') NOT NULL DEFAULT 'active',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE borrows(id INT AUTO_INCREMENT PRIMARY KEY,member_id INT NOT NULL,item_type ENUM('book','newspaper','magazine') NOT NULL,item_id INT NOT NULL,borrow_date DATE NOT NULL,due_date DATE NOT NULL,status ENUM('borrowing','returned') NOT NULL DEFAULT 'borrowing',created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,INDEX idx_borrows_item(item_type,item_id),CONSTRAINT fk_borrows_member FOREIGN KEY(member_id) REFERENCES members(id),CONSTRAINT fk_borrows_user FOREIGN KEY(created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
CREATE TABLE book_returns(id INT AUTO_INCREMENT PRIMARY KEY,borrow_id INT NOT NULL UNIQUE,return_date DATE NOT NULL,fine_amount DECIMAL(12,2) NOT NULL DEFAULT 0,note TEXT NULL,created_by INT NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_returns_borrow FOREIGN KEY(borrow_id) REFERENCES borrows(id),CONSTRAINT fk_returns_user FOREIGN KEY(created_by) REFERENCES users(id) ON DELETE SET NULL) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;
